// For each client, query PA DOS search and check status
const records = $input.first().json.data?.records || [];
const results = [];

for (const record of records) {
  const fields = record.fields || {};
  const entityNumber = fields['Entity Number'] || '';
  const entityName = fields['Entity Name'] || '';
  const email = fields['Email'] || '';
  const name = fields['Name'] || '';
  const lastKnownStatus = fields['DOS Status'] || 'unknown';

  if (!entityNumber) continue;

  results.push({
    json: {
      recordId: record.recordId,
      entityNumber,
      entityName,
      email,
      name,
      lastKnownStatus
    }
  });
}

if (results.length === 0) {
  results.push({ json: { noClients: true } });
}

return results;

const html = $input.first().json.data || $input.first().json.body || '';
const clientData = $('Split Clients').first().json;

// Parse status from DOS response HTML
// DOS returns entity status in the search results table
let currentStatus = 'unknown';
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);

// Look for status indicators in the HTML
const statusPatterns = [
  { pattern: /Active/i, status: 'Active' },
  { pattern: /Good Standing/i, status: 'Active' },
  { pattern: /Admin.*Dissolved/i, status: 'Administratively Dissolved' },
  { pattern: /Dissolved/i, status: 'Dissolved' },
  { pattern: /Cancelled/i, status: 'Cancelled' },
  { pattern: /Forfeited/i, status: 'Forfeited' },
  { pattern: /Merged/i, status: 'Merged' },
  { pattern: /Withdrawn/i, status: 'Withdrawn' },
  { pattern: /Terminated/i, status: 'Terminated' },
];

for (const { pattern, status } of statusPatterns) {
  if (pattern.test(htmlStr)) {
    currentStatus = status;
    break;
  }
}

const statusChanged = currentStatus !== 'unknown' && currentStatus !== clientData.lastKnownStatus;
const isProblematic = ['Dissolved', 'Administratively Dissolved', 'Cancelled', 'Forfeited', 'Terminated'].includes(currentStatus);

return [{
  json: {
    ...clientData,
    currentStatus,
    statusChanged,
    isProblematic,
    checkedAt: new Date().toISOString()
  }
}];
